import { Component } from '@angular/core';
import { CommonModule } from '@angular/common'; // ليعمل الـ *ngFor والـ ميزات الأساسية
import { FormsModule } from '@angular/forms';   // حل المشكلة الأساسية لتشغيل ngModel و ngForm

@Component({
  selector: 'app-home',
  standalone: true, // تأكدي أنها true
  imports: [
    CommonModule,   // إضافته هنا ضروري
    FormsModule     // إضافته هنا سيقضي على كل الأخطاء فوراً!
  ],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent {
 services = [
    { title: 'PEDIATRICIANS', image: 'https://images.unsplash.com/photo-1629909613654-28e377c37b09?w=400&auto=format&fit=crop&q=60' },
    { title: 'BRAIN SURGEONS', image: 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=400&auto=format&fit=crop&q=60' },
    { title: 'IMMUNOLOGISTS', image: 'https://images.unsplash.com/photo-1579154204601-01588f351e67?w=400&auto=format&fit=crop&q=60' }
  ];

  doctors = Array(12).fill(null).map((_, index) => ({
    name: `Dr. Alex Taylor ${index + 1}`,
    specialty: index % 2 === 0 ? 'Cardiologist' : 'Pediatrician',
    // صور أفاتار دائرية مبهجة للأطباء (تتغير تلقائياً لتجنب التكرار الممل)
    image: `https://xsgames.co/randomusers/assets/avatars/${index % 2 === 0 ? 'male' : 'female'}/${index + 10}.jpg`
  }));

  contactData = {
    firstName: '',
    lastName: '',
    mobileNumber: '',
    email: '',
    message: ''
  };

  onSubmit() {
    console.log('Form Submitted!', this.contactData);
  }
}
